const payload = $input.first().json.output ?? $input.first().json;
const rows = Array.isArray(payload.rows) ? payload.rows : [];
if (!rows.length) {
  throw new Error('ARIA non ha restituito rows[] con risultati multipli.');
}

const today = new Date().toISOString().slice(0, 10);
const seen = new Set();
const items = [];

for (const row of rows) {
  const url = String(row.url ?? '').trim();
  const title = String(row.titolo ?? '').trim();
  const key = `${url}||${title}`.toLowerCase();
  if (!url || !title || seen.has(key)) continue;
  seen.add(key);

  const keywords = Array.isArray(row.keywords)
    ? row.keywords.filter(Boolean).map((value) => String(value).trim()).join(', ')
    : String(row.keywords ?? '').trim();

  items.push({
    json: {
      data: String(row.data ?? today).trim() || today,
      categoria: String(row.categoria ?? '').trim(),
      tipo: String(row.tipo ?? '').trim(),
      titolo: title,
      fonte: String(row.fonte ?? row.url ?? '').trim(),
      keywords,
      riassunto: String(row.riassunto ?? '').trim(),
      url,
      query_usata: String(row.query_usata ?? '').trim(),
    },
  });
}

if (!items.length) {
  throw new Error('Nessun risultato unico da salvare nel foglio.');
}

return items;

const items = $input.all();
if (!items.length) {
  throw new Error('Nessun aggiornamento disponibile per l\'email.');
}

const rows = items.map((item) => item.json);
const count = rows.length;
const today = new Date().toISOString().slice(0, 10);
const sheetUrl = 'https://docs.google.com/spreadsheets/d/1b7ky-tAUfKjqOzIxp8jabMG4PWgfVmIOnz6Jv7RntUs/edit#gid=0';
const toEmail = 'Elena <REPLACE_ELENA_EMAIL>';
const fromEmail = 'ARIA <REPLACE_SMTP_SENDER_EMAIL>';

const intro = count === 1
  ? 'Oggi ho individuato 1 nuovo aggiornamento rilevante per la tua attivita\' di ricerca.'
  : `Oggi ho individuato ${count} nuovi aggiornamenti rilevanti per la tua attivita\' di ricerca.`;

const cards = rows.map((row, index) => {
  const safe = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const titolo = safe(row.titolo);
  const categoria = safe(row.categoria);
  const tipo = safe(row.tipo);
  const fonte = safe(row.fonte || row.url);
  const riassunto = safe(row.riassunto);
  const keywords = safe(row.keywords);
  const url = String(row.url ?? '').trim();
  return `
    <div style="margin:0 0 18px 0;padding:16px;border:1px solid #d9dde3;border-radius:10px;background:#ffffff;">
      <p style="margin:0 0 8px 0;font-size:12px;color:#667085;">Aggiornamento ${index + 1}</p>
      <h3 style="margin:0 0 8px 0;font-size:18px;color:#101828;">${titolo}</h3>
      <p style="margin:0 0 8px 0;font-size:14px;color:#344054;"><strong>Categoria:</strong> ${categoria} | <strong>Tipo:</strong> ${tipo}</p>
      <p style="margin:0 0 8px 0;font-size:14px;color:#344054;"><strong>Fonte:</strong> ${fonte}</p>
      <p style="margin:0 0 8px 0;font-size:14px;color:#344054;"><strong>Keywords:</strong> ${keywords}</p>
      <p style="margin:0 0 10px 0;font-size:14px;line-height:1.5;color:#101828;">${riassunto}</p>
      <p style="margin:0;"><a href="${url}" style="color:#175cd3;text-decoration:none;">Apri la fonte originale</a></p>
    </div>
  `;
}).join('');

const html = `
  <div style="font-family:Arial,Helvetica,sans-serif;background:#f5f7fa;padding:24px;color:#101828;">
    <div style="max-width:760px;margin:0 auto;background:#f5f7fa;">
      <h2 style="margin:0 0 12px 0;">Ciao Elena,</h2>
      <p style="margin:0 0 16px 0;font-size:15px;line-height:1.6;">${intro}</p>
      <p style="margin:0 0 24px 0;font-size:15px;line-height:1.6;">Di seguito trovi un riassunto sintetico delle ultime novita' raccolte da ARIA.</p>
      ${cards}
      <div style="margin-top:24px;padding:18px;border-radius:10px;background:#eaf2ff;">
        <p style="margin:0 0 10px 0;font-size:15px;"><strong>Per consultare l'elenco completo:</strong></p>
        <p style="margin:0;"><a href="${sheetUrl}" style="color:#175cd3;text-decoration:none;">Apri il Google Sheet con tutte le ricerche aggiornate</a></p>
      </div>
      <p style="margin:24px 0 0 0;font-size:14px;color:#475467;">Un saluto,<br>ARIA</p>
    </div>
  </div>
`;

return [{
  json: {
    toEmail,
    fromEmail,
    subject: `ARIA - Aggiornamento ricerche del ${today}`,
    html,
    sheetUrl,
    total_updates: count,
  },
}];
